--
-- Name: calcular_win_rate(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calcular_win_rate(p_propietario_id uuid DEFAULT NULL::uuid, p_producto_id uuid DEFAULT NULL::uuid, p_sbu_id uuid DEFAULT NULL::uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_ganadas  INTEGER;
    v_perdidas INTEGER;
BEGIN
    SELECT
        COUNT(*) FILTER (WHERE etapa = 'closed_won'),
        COUNT(*) FILTER (WHERE etapa IN ('closed_won', 'closed_lost'))
    INTO v_ganadas, v_perdidas
    FROM oportunidades
    WHERE eliminado_en IS NULL
      AND (p_propietario_id IS NULL OR propietario_id = p_propietario_id)
      AND (p_producto_id    IS NULL OR producto_id    = p_producto_id)
      AND (p_sbu_id         IS NULL OR sbu_id         = p_sbu_id);

    IF v_perdidas = 0 THEN
        RETURN 0;
    END IF;

    RETURN ROUND((v_ganadas::NUMERIC / v_perdidas) * 100, 1);
END;
$$;


