--
-- Name: mv_kpis_pipeline; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_kpis_pipeline AS
 SELECT count(*) AS total_oportunidades,
    count(*) FILTER (WHERE (oportunidades.etapa <> ALL (ARRAY['closed_won'::public.etapa_oportunidad, 'closed_lost'::public.etapa_oportunidad, 'closed_withdrawn'::public.etapa_oportunidad]))) AS oportunidades_activas,
    count(*) FILTER (WHERE (oportunidades.etapa = 'closed_won'::public.etapa_oportunidad)) AS oportunidades_ganadas,
    count(*) FILTER (WHERE (oportunidades.etapa = 'closed_lost'::public.etapa_oportunidad)) AS oportunidades_perdidas,
    COALESCE(sum(oportunidades.importe), (0)::numeric) AS pipeline_total,
    COALESCE(sum(oportunidades.importe) FILTER (WHERE (oportunidades.etapa <> ALL (ARRAY['closed_won'::public.etapa_oportunidad, 'closed_lost'::public.etapa_oportunidad, 'closed_withdrawn'::public.etapa_oportunidad]))), (0)::numeric) AS pipeline_activo,
    COALESCE(sum(oportunidades.importe) FILTER (WHERE (oportunidades.etapa = 'closed_won'::public.etapa_oportunidad)), (0)::numeric) AS importe_ganado,
    COALESCE(sum(oportunidades.importe) FILTER (WHERE (oportunidades.etapa = 'closed_lost'::public.etapa_oportunidad)), (0)::numeric) AS importe_perdido,
    COALESCE(avg(oportunidades.importe) FILTER (WHERE (oportunidades.etapa = 'closed_won'::public.etapa_oportunidad)), (0)::numeric) AS ticket_medio_ganado,
    public.calcular_win_rate() AS win_rate_global,
    now() AS calculado_en
   FROM public.oportunidades
  WHERE (oportunidades.eliminado_en IS NULL)
  WITH NO DATA;


--
-- Name: mv_pipeline_por_etapa; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_pipeline_por_etapa AS
 SELECT oportunidades.etapa,
    count(*) AS num_oportunidades,
    sum(oportunidades.importe) AS importe_total,
    avg(oportunidades.importe) AS importe_medio
   FROM public.oportunidades
  WHERE ((oportunidades.eliminado_en IS NULL) AND (oportunidades.etapa <> ALL (ARRAY['closed_won'::public.etapa_oportunidad, 'closed_lost'::public.etapa_oportunidad, 'closed_withdrawn'::public.etapa_oportunidad])))
  GROUP BY oportunidades.etapa
  ORDER BY (sum(oportunidades.importe)) DESC
  WITH NO DATA;


