    usuario_id uuid NOT NULL,
    alertas_pipeline boolean DEFAULT true NOT NULL,
    briefing_diario boolean DEFAULT false NOT NULL,
    alerta_win_rate boolean DEFAULT true NOT NULL,
    hora_briefing time without time zone DEFAULT '08:00:00'::time without time zone NOT NULL,
    umbral_win_rate numeric(5,2) DEFAULT 60.00 NOT NULL,
    voz_tts character varying(50) DEFAULT 'es-ES'::character varying NOT NULL,
    duracion_podcast_min integer DEFAULT 5 NOT NULL,
    creado_en timestamp with time zone DEFAULT now() NOT NULL,
    actualizado_en timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT notificaciones_config_duracion_podcast_min_check CHECK (((duracion_podcast_min >= 1) AND (duracion_podcast_min <= 30)))
);


